long long cross(Point a, Point b, Point c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

bool isInside(Point p, Point a, Point b, Point c) {
    long long ori_abc = cross(a, b, c);
    long long ori_abp = cross(a, b, p);
    long long ori_bcp = cross(b, c, p);
    long long ori_cap = cross(c, a, p);

    if (ori_abc > 0) {
