bool isConvex(vector<Point>& quad) {
    if (quad.size() != 4) return false;
    for (int i = 0; i < 4; i++) {
        vector<Point> tri;
        for (int j = 0; j < 4; j++) {
            if (j != i) {
                tri.push_back(quad[j]);
            }
        }
        if (isInside(quad[i], tri[0], tri[1], tri[2])) {
            return false;
        }
    }
    return true;
}

vector<Point> getConvexHullOrder(vector<Point> quad) {
    int idx = 0;
    for (int i = 1; i < 4; i++) {
        if (quad[i].x < quad[idx].x || (quad[i].x == quad[idx].x && quad[i].y < quad[idx].y)) {
            idx = i;
        }
    }
    swap(quad[0], quad[idx]);
    Point p0 = quad[0];
    sort(quad.begin() + 1, quad.end(), [p0](const Point& a, const Point& b) {
        long long dx1 = a.x - p0.x;
        long long dy1 = a.y - p0.y;
        long long dx2 = b.x - p0.x;
        long long dy2 = b.y - p0.y;
        long long cross_product = dx1 * dy2 - dy1 * dx2;
        if (cross_product != 0) {
            return cross_product > 0;
        }
        long long d1 = dx1 * dx1 + dy1 * dy1;
        long long d2 = dx2 * dx2 + dy2 * dy2;
        return d1 < d2;
    });
    return quad;
}

bool isTrapezoid(vector<Point> hull) {
    vector<pair<long long, long long>> slopes;
    for (int i = 0; i < 4; i++) {
        int next = (i + 1) % 4;
        long long dx = hull[next].x - hull[i].x;
        long long dy = hull[next].y - hull[i].y;
        if (dx == 0 && dy == 0) {
            continue;
        }
        if (dx == 0) {
            slopes.push_back({0, 1});
        } else if (dy == 0) {
            slopes.push_back({1, 0});
        } else {
            long long g = gcd(abs(dx), abs(dy));
            dx /= g;
            dy /= g;
            if (dx < 0) {
                dx = -dx;
                dy = -dy;
            }
            slopes.push_back({dx, dy});
        }
    }
    if (slopes.size() != 4) {
        return false;
    }
    if (slopes[0] == slopes[2] || slopes[1] == slopes[3]) {
        return true;
    }
    return false;
}

