    if (n < 4) return 0;

    map<pair<long long, long long>, long long> midCount;
    for (int i = 0; i < n; i++) {
        for (int j = i+1; j < n; j++) {
            long long midX = points[i][0] + points[j][0];
            long long midY = points[i][1] + points[j][1];
            midCount[{midX, midY}]++;
        }
    }
    long long T2 = 0;
    for (const auto& it : midCount) {
        long long cnt = it.second;
        T2 += cnt * (cnt-1) / 2;
    }

    using SlopeKey = pair<long long, long long>;
    map<SlopeKey, vector<tuple<long long, int, int>>> slopeMap;

    for (int i = 0; i < n; i++) {
        for (int j = i+1; j < n; j++) {
            long long x1 = points[i][0];
            long long y1 = points[i][1];
            long long x2 = points[j][0];
            long long y2 = points[j][1];
            long long dx = x2 - x1;
            long long dy = y2 - y1;

            if (dx == 0 && dy == 0) 
                continue;

            if (dx == 0) {
                dy = 1;
            } else if (dy == 0) {
                dx = 1;
            } else {
                if (dx < 0) {
                    dx = -dx;
                    dy = -dy;
                }
                long long g = gcd(dx, dy);
                dx /= g;
                dy /= g;
            }

            long long intercept = dy * x1 - dx * y1;
            slopeMap[{dx, dy}].push_back({intercept, i, j});
        }
    }

    long long total_slope_group_sum = 0;

    for (auto& p : slopeMap) {
        vector<tuple<long long, int, int>>& vec = p.second;
        long long m = vec.size();
        if (m < 2) continue;

        unordered_map<int, int> global_deg;
        for (auto& seg : vec) {
            long long intercept_val;
            int i, j;
            tie(intercept_val, i, j) = seg;
            global_deg[i]++;
            global_deg[j]++;
        }

        long long total_pairs = m*(m-1)/2;
        long long shared_pairs_global = 0;
        for (auto& kv : global_deg) {
            long long count = kv.second;
            shared_pairs_global += count*(count-1)/2;
        }
        long long disjoint_whole = total_pairs - shared_pairs_global;

        map<long long, vector<pair<int, int>>> interceptMap;
        for (auto& seg : vec) {
            long long inter_val;
            int i, j;
            tie(inter_val, i, j) = seg;
            interceptMap[inter_val].push_back({i, j});
        }

        for (auto& p_inter : interceptMap) {
            vector<pair<int, int>>& seg_list = p_inter.second;
            long long m_i = seg_list.size();
            if (m_i < 2) continue;

            unordered_map<int, int> local_deg;
            for (auto& seg : seg_list) {
                int i = seg.first;
                int j = seg.second;
                local_deg[i]++;
                local_deg[j]++;
            }

            long long shared_pairs_local = 0;
            for (auto& kv : local_deg) {
                long long count = kv.second;
                shared_pairs_local += count*(count-1)/2;
            }
            long long total_pairs_i = m_i*(m_i-1)/2;
            long long disjoint_pairs_local = total_pairs_i - shared_pairs_local;
            disjoint_whole -= disjoint_pairs_local;
        }

        total_slope_group_sum += disjoint_whole;
    }

    long long ans = total_slope_group_sum - T2;
    return ans;
}
